head.script:
//-------------------------------------------------------------------------
// scwin.name : 
// scwin.desc : 전역변수 선언
//-------------------------------------------------------------------------  
scwin.pos_rowSts = 0;
scwin.pos_wrkPlCd = null;
scwin.skipWrkplGuardBySortOnce = false;
scwin._wrkplGridGuardEventsBound = false;
//scwin.MSG_LO_ERR_005 = "지역코드는 6자리의 코드를 지역명은 두글자 이상 입력후 조회바랍니다.";
scwin.MSG_LO_ERR_006 = "작업장 코드가 비어있습니다";
scwin.MSG_LO_ERR_007 = "작업장코드 생성규칙이 적절하지 않습니다.";
scwin.MSG_LO_ERR_009 = "지역은 필수 입력 사항입니다.";

scwin.onpageload = function() {
    //공통코드 적용
    const codeOptions = [
         { grpCd: "LO115", compID: "acb_WrkPlPosnClsCd"}         //소유구분
        ,{ grpCd: "LO116", compID: "acb_OwnerCd" }              //소유주
        ,{ grpCd: "LO121", compID: "acb_wrkPlClsCd", opt :{"range" : "1,03"} }          //작업장구분 GauceUtil.getCodeList("LO121",1,"03");
    ];
    $c.data.setCommonCode(codeOptions);
};

// 공통코드가 셋팅이 되고 scwin.ondataload 이벤트가 호출
scwin.ondataload = function() {
//     let dltStr = "dlt_commonCodeLO121"; // "dlt_commonCode" + 그룹코드값으로 데이터리스트 조합
//     let dlt = $c.gus.object(dltStr); // 데이터 리스트 객체
//     $c.data.dataListFilter(dlt, "fltrCd1 == '03'");  //$c.data.dataListFilter 함수를 이용해서 필터
}

//-------------------------------------------------------------------------
// scwin.name : f_OnLoad
// scwin.desc : 화면로딩시 
//-------------------------------------------------------------------------   
scwin.f_OnLoad = function() {	
};

scwin.onUdcCompleted = function() {
	scwin.f_defaultValue();

};


//-------------------------------------------------------------------------
// scwin.name : f_defaultValue
// scwin.desc : 화면 open시 초기 데이타 setting
//-------------------------------------------------------------------------
scwin.f_defaultValue = function() {
	$c.gus.cfDisableKey();
	$c.gus.cfDisableBtn([btn_save]);
	$c.gus.cfDisableObjects([oRecevInfo]);
    acb_wrkPlClsCd.setDisabled(true);
    udc_adddistrict.setDisabled(true);
	ed_cnd_wrkPlNm.focus();
};


scwin.f_addRow_gr_wrkpl = async function() {
    scwin.f_ds_district_copy();
    const newRowIndex = ds_wrkpl.getRowCount();
    const oldRowIndex = ds_wrkpl.getRowPosition();

    // oRecevInfo 
    if ( !$c.util.isEmpty( oldRowIndex ) ) {
        let chk = await scwin.f_ReqFieldChk(oldRowIndex);
        if ( chk == false ) {
            ds_wrkpl.setEventPause("onrowpositionchange",true);
            gr_wrkpl.setFocusedCell(oldRowIndex,0);
            ds_wrkpl.setEventPause("onrowpositionchange",false);
            if ( typeof chk.comObj == "function") {
                chk.comObj();
            } else {
                if ( chk?.comObj?.focus ) {
                    chk.comObj.focus();
                }
            }
            return false;
        }
        $c.gus.cfEnableBtnOnly([btn_save]);
        ds_wrkpl.insertRow(newRowIndex);
        acb_wrkPlClsCd.setDisabled(false);
        acb_wrkPlClsCd.setValue("R");
        // 기본 입력 값 설정 
        ds_wrkpl.setCellData(newRowIndex,"hndlRateOutbrYn"  ,0);       // 조작료발생여부
        ds_wrkpl.setCellData(newRowIndex,"preInfoSndYn"     ,0);       // 사전정보전송여부
        ds_wrkpl.setCellData(newRowIndex,"gatelogSndYn"     ,0);       // GateLog전송여부
        ds_wrkpl.setCellData(newRowIndex,"ediSndYn"         ,0);       // EDI사용여부
        ds_wrkpl.setCellData(newRowIndex,"cntrRgnWrkPlYn"   ,1);       // CNTR작업장여부
        ds_wrkpl.setCellData(newRowIndex,"cgshfRateOutbrYn" ,0);       // 이적료발생여부 
        ds_wrkpl.setCellData(newRowIndex,"useYn"            ,1);       // 사용 여부 
        gr_wrkpl.setFocusedCell(newRowIndex, "wrkPlClsNm", false);
    }


};

scwin.f_delRow_gr_wrkpl = async function(){
    const oldRowIndex = ds_wrkpl.getRowPosition();
    const newRowIndex = oldRowIndex - 1;
    if ( oldRowIndex < 0 ) return false;
    if ( ds_wrkpl.getRowStatus(oldRowIndex) == "C" ) {
        const rowFilterCount = ds_district.getRowCount();
        for ( let rowIdx = 0 ; rowIdx < rowFilterCount ; rowIdx ++) {
            scwin.f_rowUndo(ds_district,[rowIdx]);
        }
        scwin.f_rowUndo(gr_wrkpl, [oldRowIndex]);
    } else {
        if( oldRowIndex > -1) {
            $c.data.deleteRow(gr_wrkpl);
            const rowFilterCount = ds_district.getRowCount();
            for ( let rowIdx = 0 ; rowIdx < rowFilterCount ; rowIdx ++) {
                ds_district.setRowPosition(rowIdx);
                $c.data.deleteRow(ds_district);
            }
            let chk = await scwin.f_ReqFieldChk(oldRowIndex);
            if ( chk == false ) {
                //ds_wrkpl.setEventPause("onrowpositionchange",true);
                gr_wrkpl.setFocusedCell(oldRowIndex,0);
                //ds_wrkpl.setEventPause("onrowpositionchange",false);
                if ( typeof chk.comObj == "function") {
                    chk.comObj();
                } else {
                    if ( chk?.comObj?.focus ) {
                        chk.comObj.focus();
                    }
                }
                return false;
            }
            gr_wrkpl.setFocusedCell(newRowIndex, 0);
            scwin.f_districtFilter();
        }
    }
}
scwin.f_cancel_gr_wrkpl = function(){
    scwin.f_rowUndo(gr_wrkpl, true);
}

scwin.f_addRow_gr_district = function() {
    $c.gus.cfEnableBtnOnly([btn_save]);
    if (ds_wrkpl.getCellData(ds_wrkpl.getRowPosition(),"wrkPlCd") == "") {
        $c.win.alert(scwin.MSG_LO_ERR_006);
        return;
    }

    var row = ds_district.getRowCount();
    ds_district.insertRow(row);
    ds_district.setCellData(row,"wrkPlCd",ds_wrkpl.getCellData(ds_wrkpl.getRowPosition(),"wrkPlCd"));
    ds_district.setCellData(row,"wrkPlNm",ds_wrkpl.getCellData(ds_wrkpl.getRowPosition(),"wrkPlNm"));
    gr_district.setFocusedCell(row, "districtCd", false);
}

scwin.f_rowUndo = function(gridObj,rowIndexList=[]) {
    let rowIdxs = [];
    const length = gridObj.getRowCount();
    if ( rowIndexList instanceof Array ) {
        rowIndexList = rowIndexList.length == 0 ? Array.from({ length }, (_, i) => i ) : rowIndexList;
        rowIdxs = rowIndexList.filter(f=> f > -1 );
    } else {
        rowIdxs =  gridObj.getAllFocusedRowIndex();
    }
    let dataList = $p.getComponentById(gridObj.getDataList());
    let removeIdx = [];
    let undoIdx = [];
    let onlyRFlag = false;
    for(let idx in rowIdxs) {
        var row = rowIdxs[idx];
        if (dataList.getRowStatus(row) == "C") {
            removeIdx.push(row);
            onlyRFlag = true;
        } else {
            undoIdx.push(row);
            if(onlyRFlag) {
                onlyRFlag = false;
            }
        }
    }
    let tRemoveIdx = removeIdx.length;
    let tUndoIdx = undoIdx.length;

    if(removeIdx.length > 0) {
        dataList.removeRows(removeIdx);
        if(onlyRFlag) {
            if(dataList.getRowCount() > 0) {
                if(dataList.getRowCount() -1 < removeIdx[0]) {
                    gridObj.setFocusedCell(dataList.getRowCount() -1, 0);
                } else {
                    gridObj.setFocusedCell(removeIdx[0], 0);
                }

            }
        }
    }
    if(undoIdx.length > 0) {
        dataList.undoRows(undoIdx);
        if(dataList.getRowCount() > 0) {
            gridObj.setFocusedCell(undoIdx[tUndoIdx -1],0);
        }
    }    
}


//-------------------------------------------------------------------------
// scwin.name : f_Retrieve
// scwin.desc : 조회
//-------------------------------------------------------------------------

scwin.f_Retrieve = function() {
    scwin.gr_wrkpl_sortOptions = gr_wrkpl.getSortableStatus().reduce((s,a,i)=>{ 
            if ( !s["sortIndex"] ) s["sortIndex"] = "";
            if ( !s["sortOrder"] ) s["sortOrder"] = ""; 
            s["sortIndex"] += ( i == 0 ? "" : " " ) + a["colID"]; 
            s["sortOrder"] += ( i == 0 ? "" : " " ) + a["sortOrder"]; 
            return s;
    }, {});
    ds_wrkpl.removeAll();
    ds_district.removeAll();
    ds_district_send.removeAll();
    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail

    var rowcnt = ds_wrkpl.getRowCount();
    if (rowcnt == 0) {
		$c.win.alert(MSG_CM_WRN_002);
        gr_wrkpl.setFocusedCell(0, 0);
	} else {
		$c.gus.cfEnableObjects([oRecevInfo]);
		$c.gus.cfDisableKey();
        if ( scwin.gr_wrkpl_sortOptions && scwin.gr_wrkpl_sortOptions["sortIndex"] ) {
            ds_wrkpl.multisort(scwin.gr_wrkpl_sortOptions);
        }
        // gr_wrkpl.setFocusedCell(scwin?.pos_rowSts||0, 0);
        let ds_wrkpl_pos = 0;
        ds_wrkpl.setIgnoreStatus("rowIndex", true);
        ds_wrkpl.getAllJSON().forEach((row,rowIndex)=>{
            if ( !$c.util.isEmpty( scwin.pos_wrkPlCd ) ) {
                if ( row.wrkPlCd == scwin.pos_wrkPlCd ) {
                    ds_wrkpl_pos = rowIndex;
                }
            }
            ds_wrkpl.setCellData(rowIndex,"rowIndex", rowIndex);
        });


        gr_wrkpl.setFocusedCell(ds_wrkpl_pos, 0);

	}
    scwin.pos_rowSts = 0;
    scwin.pos_wrkPlCd = null;
    tbx_totalRows.setValue(rowcnt);
    $c.gus.cfDisableBtn([btn_save]);
    acb_wrkPlClsCd.setDisabled(true);
    udc_adddistrict.setDisabled(false);

};
scwin.sbm_retrieve_submiterror = function (e) {

};

//-------------------------------------------------------------------------
// scwin.name : f_Save
// scwin.desc : 저장
//-------------------------------------------------------------------------


scwin.f_ds_district_copy = function() {
    const sendList = ds_district.getAllJSON().filter(f=>f.rowStatus != "R");
    ds_district_send.removeAll();
    sendList.forEach((rowJson,rowIndex)=>{
        ds_district_send.setRowJSON(rowIndex, rowJson);
        ds_district_send.modifyRowStatus(rowIndex, rowJson.rowStatus);
    });
}

scwin.f_Save = async function() {
    scwin.f_ds_district_copy();

	if (ds_wrkpl.getModifiedJSON().length == 0 && ds_district_send.getModifiedJSON().length == 0) {
		$c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_001, ["철도역"]));
  		return false;
	}

	ed_wrkPlNm.setValue(ed_wrkPlNm.getValue().trim());
    let chk = await scwin.f_ReqFieldChk_save();
	if (chk) {	
        chk = await $c.win.confirm(MSG_CM_CRM_001);
    	if ( chk ) {
           	scwin.pos_rowSts  = ds_wrkpl.getRowPosition();
            scwin.pos_wrkPlCd = ds_wrkpl.getCellData(scwin.pos_rowSts,"wrkPlCd");
            $c.sbm.execute(sbm_save);
    	}
    }
};

scwin.f_ReqFieldChk_save = async function(rowIndex) {
	//필수입력항목 체크
    if (rd_UseYn.getValue() == "" ) {
    	await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("사용여부")); 
  		return false;
    }

	if (acb_wrkPlClsCd.getValue() == "" ) {
    	await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("작업장구분")); 
  		return false;
    }



    // oRecevInfo
    let chk = await $c.gus.cfValidate([oRecevInfo]);
    if ( !chk ) {
        return false;
    }
    chk = await $c.gus.cfValidate([gr_district], null, true);
	if ( !chk ) {	    	
  		return false;
	} 

    if ( ed_lobranCd.getValue() == "" ) {
    	await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("소속점소")); 
        ed_lobranCd.focus();
  		return false;
    }


    if ( ds_wrkpl.getRowStatus(ds_wrkpl.getRowPosition()) == "C" && 
    	(ed_lobranCd.getValue().substr(0,1) + acb_wrkPlClsCd.getValue()) != ed_wrkPlCd.getValue().substr(0,2) && 
    	acb_wrkPlClsCd.getValue() != "G")  {
    	await $c.win.alert(scwin.MSG_LO_ERR_007);
    	ed_wrkPlCd.setValue(ed_lobranCd.getValue().substr(0,1) + acb_wrkPlClsCd.getValue() + ed_wrkPlCd.getValue().substr(2,3));

    	for (i=0 ; i< ds_district.getRowCount(); i++) {
    		ds_district.setCellData(i,"wrkPlCd",ed_lobranCd.getValue().substr(0,1) + acb_wrkPlClsCd.getValue() + ed_wrkPlCd.getValue().substr(2,3));
    	}
		return false;
    }

    // 철도역별 지역코드 Check
    const checkList = ds_wrkpl.getAllJSON().filter(f => {
        const rowStatusCheck     = ['C','U'].includes(f.rowStatus);    // 등록 수정 일경우 
        const districtCountCheck = ds_district.getAllJSON().filter(fc=>fc.wrkPlCd == f.wrkPlCd).length == 0; // 소속 지역 건수 가 O인 경우 
        return rowStatusCheck && districtCountCheck;
    });

    if( checkList.length > 0 ) {
    	await $c.win.alert(scwin.MSG_LO_ERR_009);
    	return false;
    }

	return true;
};


scwin.f_ReqFieldChk = async function(rowIndex) {
    const resultInfo = function(check, comObj) {
        return {
            comObj,
            valueOf() {
                return check;
            }
        }
    }
    if ( rowIndex < 0 ) return true;

    const { rowStatus, wrkPlClsCd, lobranCd, wrkPlCd, wrkPlNm, useYn , zip, addr1, addr2, korailStnCd} = ds_wrkpl.getRowJSON(rowIndex);

	if ( wrkPlClsCd == "" ) {
    	await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("작업장구분")); 
  		return resultInfo(false,acb_wrkPlClsCd);
    }

	if ( wrkPlCd == "" ) {
    	await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("작업장코드"));
        return resultInfo(false,ed_wrkPlCd);
    }


    if ( lobranCd == "" && ( rowStatus == "C" || rowStatus == "U" )) { 
    	await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("소속점소")); 
        return resultInfo(false,ed_lobranCd);
    }

    if ( wrkPlNm == "" || wrkPlNm.length > 50 ) {
    	await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("작업장명")); 
        return resultInfo(false,ed_wrkPlNm);
    }    
    if ( zip == "" ) {
    	await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("우편번호")); 
        return resultInfo(false,ed_zip);
    }

    if ( addr1 == "" ) {
    	await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("주소")); 
        return resultInfo(false,ed_addr1);
    }

    if ( addr2 == "" || addr2.length > 50 ) {
    	await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("상세주소")); 
        return resultInfo(false,ed_addr2);
    }    

    if ( korailStnCd == "" || korailStnCd.length > 6 ) {
    	await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("철도청역코드")); 
        return resultInfo(false,ed_korailStnCd);
    }    


	//필수입력항목 체크
    if ( useYn == "" ) {
    	await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("사용여부"));
  		return false;
    }

    const districtList = ds_district.getAllFilteredJSON();


    // 소속 지역코드 필수 CHECK 
    const districtMsg = $c.str.attachPostposition("지역코드");
    // - 건수 
    if ( districtList.length == 0 && rowStatus == "D" ) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("지역코드")); 
        return false;
    }

    // 소속점소
    // await $c.gus.cfAlertMsg(`소속지역의 ${N}번재 데이터에서 지역코드은(는) 필수 입력 항목입니다.`);
    const emptyCheckList = districtList.map((o,row)=>{ return { ...o,row }}).filter(f=> f["districtCd"] + f["districtNm"] == "");
    if ( emptyCheckList.length > 0 ) {
        const emptyRowIndex = emptyCheckList.at(0)["row"];
        await $c.gus.cfAlertMsg(`소속지역의 ${emptyRowIndex + 1}번재 데이터에서 ${districtMsg} 필수 입력 항목입니다.`);
        return false;
    }

    // - 중복 
    // 소속지역의 N번재 데이터에서 지역코드은(는) 중복될 수 없습니다.   N  - 1 아님
    const duplicateKey = "districtCd";
    const keyMap = districtList.reduce((acc, item, idx) => {
        acc[item[duplicateKey]] = acc[item[duplicateKey]] ?? [];
        acc[item[duplicateKey]].push(idx);
        return acc;
    }, {});

    const duplicateList = Object.entries(keyMap).filter(([key, rows]) => rows.length > 1).map(([key, rows]) => {
            const [first, ...duplicates] = rows;
            return { key, minRow: Math.min(...duplicates), first, duplicates };
    });
    console.log("result===>" , duplicateList);
    if ( duplicateList.length > 0 ) {
        const duplicateInfo =  duplicateList.at(0);
        await $c.gus.cfAlertMsg(`소속지역의 ${duplicateInfo["minRow"] + 1}번재 데이터에서 ${districtMsg} 중복될 수 없습니다.`);
        return false;
    }
    // rowIndex
    if ( rowStatus == "C" &&  ( lobranCd.substr(0,1) + wrkPlClsCd ) != wrkPlCd.substr(0,2) && wrkPlClsCd != "G")  {
    	await $c.win.alert(scwin.MSG_LO_ERR_007);
        const failFn = function(){
            ed_wrkPlCd.setValue(ed_lobranCd.getValue().substr(0,1) + acb_wrkPlClsCd.getValue() + ed_wrkPlCd.getValue().substr(2,3));
            for (i=0 ; i< ds_district.getRowCount(); i++) {
                ds_district.setCellData(i,"wrkPlCd",ed_lobranCd.getValue().substr(0,1) + acb_wrkPlClsCd.getValue() + ed_wrkPlCd.getValue().substr(2,3));
            }
        }
		return resultInfo(false,failFn);
    }
    const sendList = districtList.filter(f=>f.rowStatus != "D" );
    // 소속점소 목록이 없는 경우 
    if( rowStatus != "D" && sendList.length == 0 ) {
    	await $c.win.alert(scwin.MSG_LO_ERR_009);
    	return false;
    }

	return true;
};

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
    await $c.win.alert(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    scwin.f_Retrieve();
};

scwin.sbm_save_submiterror = function (e) {
    //cfShowError(e);
};


//-------------------------------------------------------------------------
// scwin.name : f_winOpen
// scwin.desc : 화면이동
//-------------------------------------------------------------------------
scwin.f_winOpen = async function() {

    if (ed_wrkPlCd.getValue().trim() == "") {
  		$c.win.alert(scwin.MSG_LO_ERR_006);	// 작업장 코드가 비어있습니다.
		return;
	} else {
        // 하위작업장 호출 
        let data = {
            wrkPlCd : ed_wrkPlCd.getValue().trim(),
            wrkPlNm : ed_wrkPlNm.getValue().trim()
        };

        let win_url = "/ui/ds/lo/comninfomgnt/lo_100_07_06p.xml";
        let opts = {
            id : "smpPop"
            , popupName : "하위작업장관리"
            , modal : true
            , type : "browserPopup"
            , width : 540
            , height : 700
        };

        var	rt = await $c.win.openPopup(win_url, opts, data);
    }
};

//-------------------------------------------------------------------------
// 조회조기 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function() {
	$c.gus.cfInitObjects(tbl_search,null);
	//f_defaultValue();
};

scwin.gr_wrkpl_onrowindexchange = async function (rowIndex, oldRow) { return false;
    if ( scwin._revertingNode == true ) {
        scwin._revertingNode = false;
        return false;
    }
    if ( oldRow != null && oldRow  > -1 ) {
        const chk = await scwin.f_ReqFieldChk(oldRow);
        if ( chk == false ) {
            scwin._revertingNode = true;
            gr_wrkpl.setFocusedCell(oldRow,0);
            if ( typeof chk.comObj == "function") {
                chk.comObj();
            } else {
                if ( chk.comObj.focus ) {
                    chk.comObj.focus();
                }
            }
            return false;
        }
    }    
	if ( rowIndex > -1 ){

		$c.gus.cfPrepareObjectHidVal(ds_wrkpl, rowIndex, ["lobranCd", 	"lobranNm",		"upperWrkPlCd",		"upperWrkPlNm"],  
											 [ed_lobranCd, ed_lobranNm,	ed_upperWrkPlCd,	ed_upperWrkPlNm]);
		$c.gus.cfEnableObjects([oRecevInfo]);

   		if ( ds_wrkpl.getRowStatus(rowIndex) == "C") {
			$c.gus.cfDisableObjects([ed_zip, ed_addr1]);
		} else {
			$c.gus.cfDisableKey();
			$c.gus.cfDisableObjects([ed_zip, ed_addr1]);
		}
	}
    if (ds_wrkpl.getRowStatus(rowIndex) == "C") {
		acb_wrkPlClsCd.setDisabled(false);
	} else {
        acb_wrkPlClsCd.setDisabled(true);
	}    

    //콤보박스 값 세팅
    acb_wrkPlClsCd.setValue(ds_wrkpl.getCellData(rowIndex, "wrkPlClsCd"));
    acb_WrkPlPosnClsCd.setValue(ds_wrkpl.getCellData(rowIndex, "wrkPlPosnClsCd"));
    acb_OwnerCd.setValue(ds_wrkpl.getCellData(rowIndex, "ownerCd"));

	scwin.f_districtFilter();
    tbx_totalRows2.setValue(ds_district.getRowCount());
};
scwin._revertingNode = false;
scwin.ds_wrkpl_onrowpositionchange = async function (info) { 
    if ( scwin._revertingNode ) { scwin._revertingNode = false; return false; }    
    const {  newRowIndex : rowIndex ,  oldRowIndex : oldRow } = info;
    if ( rowIndex == null ) return false;
    if ( oldRow != null && oldRow  > -1 ) {
        const chk = await scwin.f_ReqFieldChk(oldRow);
        if ( chk == false ) {
            scwin._revertingNode = true;
//            gr_wrkpl.setEventPause("onrowpositionchange",false);
//            ds_wrkpl.setEventPause("onrowpositionchange",false);
            gr_wrkpl.setFocusedCell(oldRow,0);
//            ds_wrkpl.setEventPause("onrowpositionchange",true);
//            gr_wrkpl.setEventPause("onrowpositionchange",true);
            if ( typeof chk.comObj == "function") {
                chk.comObj();
            } else {
                if ( chk?.comObj?.focus ) {
                    chk.comObj.focus();
                }
            }
            return false;
        }
    }    
	if ( rowIndex > -1 ){

		$c.gus.cfPrepareObjectHidVal(ds_wrkpl, rowIndex, ["lobranCd", 	"lobranNm",		"upperWrkPlCd",		"upperWrkPlNm"],  
											 [ed_lobranCd, ed_lobranNm,	ed_upperWrkPlCd,	ed_upperWrkPlNm]);
		$c.gus.cfEnableObjects([oRecevInfo]);

   		if ( ds_wrkpl.getRowStatus(rowIndex) == "C") {
			$c.gus.cfDisableObjects([ed_zip, ed_addr1]);
		} else {
			$c.gus.cfDisableKey();
			$c.gus.cfDisableObjects([ed_zip, ed_addr1]);
		}
	}
    if (ds_wrkpl.getRowStatus(rowIndex) == "C") {
		acb_wrkPlClsCd.setDisabled(false);
	} else {
        acb_wrkPlClsCd.setDisabled(true);
	}    

    //콤보박스 값 세팅
    acb_wrkPlClsCd.setValue(ds_wrkpl.getCellData(rowIndex, "wrkPlClsCd"));
    acb_WrkPlPosnClsCd.setValue(ds_wrkpl.getCellData(rowIndex, "wrkPlPosnClsCd"));
    acb_OwnerCd.setValue(ds_wrkpl.getCellData(rowIndex, "ownerCd"));

	scwin.f_districtFilter();
    tbx_totalRows2.setValue(ds_district.getRowCount());
    gr_wrkpl.render.focus();

};

scwin.gr_district_onrowindexchange = function (rowIndex, oldRow) {
    if (ds_district.getRowStatus(rowIndex) == "C") {
		gr_district.setReadOnly(false);
	} else {
        gr_district.setReadOnly(true);
	}
};

