scwin.gr_district_onafteredit = function (rowIndex, columnIndex, value) {
    const columnId = gr_district.getColumnID(columnIndex);
    if(columnId == "districtCd") {
        if( value != scwin.districtCd_oldValue) {
            ds_district.setCellData(rowIndex, "districtNm", "");
            if ( value != "" ) {
                scwin.f_openLobranPopUp("udc_comCode_comm_grid",value,"", "T");
            }
        }
    } else if ( columnId == "districtNm" ) {
        if( value != scwin.districtNm_oldValue) {
            ds_district.setCellData(rowIndex, "districtCd", "");
            if ( value != "" ) {
                scwin.f_openLobranPopUp("udc_comCode_comm_grid","",value, "T");
            }
        }
    }
};


