//-------------------------------------------------------------------------
// 조회 소속 점소, 상위작업장, 소속점소, 귀속물류점소 팝업화면 호출 되는 함수 START 
//------------------------------------------------------------------------- 

scwin.f_openLobranPopUp = async function(udcGubun, code, name , winCloseTF = "T", ..._lobranParam ) {
    lobranParam = {
        udc_cnd_lobranCd      : ['5', null, '150,170', null,'A,B'    , '440', '500', null, null, null, "F", null],   // 조회 소속점소
        udc_lobranCd          : ['5', null, '150,170', null,'A,B'    , '440', '500', null, null, null, "F", null],   // 입력 소속점소
        udc_blngLobranCd      : ['5', null, '150,170', null,',,,,,,1', '440', '500', null, null, null, "F", null],   // 귀속 소속점소
        udc_upperWrkPlCd      : ['5', null, '150,170', null, null    , '440', '500', null, null, null, 'F', null],   // 상위 작업장 
        udc_comCode_comm_grid : ['5', "지역코드,지역명" ,'150,210' ,null ,"2,3,,,RG" ,'440' ,'500' ,null ,null ,null ,'F' ,"지역,지역코드,지역명" ],   // 소속지역 그리드 지역
    }
    if ( $c.util.isEmpty(_lobranParam) ) {
        _lobranParam = lobranParam[udcGubun];
    }
    const udcCommComp = $c.util.getComponent(udcGubun);
    const rtnList = await udcCommComp.cfCommonPopUpAsync(await function(rtnList) { return rtnList;}, code,name, winCloseTF, ..._lobranParam);
    let rtnCode, rtnName , rtnEtcList; 

    if (rtnList != null ) {
        if ( rtnList == "N/A" ||  rtnList[0] == "N/A"){
            [rtnCode, rtnName ] = ["",""]; 
		} else {
            [rtnCode, rtnName, ...rtnEtcList ] = rtnList;
        }
    }
    let rowIndex = ds_wrkpl.getRowPosition();
    if ( udcGubun == "udc_cnd_lobranCd" )  {
        ds_view_cond.set("lobranCd" , rtnCode );
        ds_view_cond.set("lobranNm" , rtnName );
    } else if ( udcGubun == "udc_lobranCd" )  {
        ds_wrkpl.setCellData(rowIndex, "lobranCd" , rtnCode );
        ds_wrkpl.setCellData(rowIndex, "lobranNm" , rtnName );
    } else if ( udcGubun == "udc_blngLobranCd" )  {
        ds_wrkpl.setCellData(rowIndex, "blngLobranCd" , rtnCode );
        ds_wrkpl.setCellData(rowIndex, "blngLobranNm" , rtnName );
    } else if ( udcGubun == "udc_upperWrkPlCd" )  {
        ds_wrkpl.setCellData(rowIndex, "upperWrkPlCd" , rtnCode );
        ds_wrkpl.setCellData(rowIndex, "upperWrkPlNm" , rtnName );
    } else if ( udcGubun == "udc_comCode_comm_grid" ){
        rowIndex = ds_district.getRowPosition();
        ds_district.setCellData(rowIndex, "districtCd" , rtnCode );
        ds_district.setCellData(rowIndex, "districtNm" , rtnName );
    }
}
