scwin.f_GridToExcel = async function(){    
    if ( ds_wrkpl.getRowCount() <= 0) {
        $c.win.alert("내역이 존재하지않습니다.");
        return false;
    }
    let fileName  = '철도역목록.xlsx';
    let sheetName = '철도역목록';
    await $c.data.downloadGridViewExcel(gr_wrkpl, { fileName, sheetName , hiddenVisible : true });    
}

