};


scwin.acb_WrkPlPosnClsCd_onviewchange = function (info) {
    var rowIndex = ds_wrkpl.getRowPosition();
    if(info.newValue != ds_wrkpl.getCellData(rowIndex, "wrkPlPosnClsCd")){
        ds_wrkpl.setCellData(rowIndex, "wrkPlPosnClsCd",info.newValue);
    }

    var strPosClsCd = ds_wrkpl.getCellData(rowIndex, "wrkPlPosnClsCd");
    if (strPosClsCd == "T" || strPosClsCd == "L" ) {
		acb_OwnerCd.setDisabled(false);
	}else {
        acb_OwnerCd.setDisabled(true);
        acb_OwnerCd.setValue("");
	}
};

