scwin.btn_zip_onclick = async function (e) {
    var options = {
        id: "newzipcodePopup",
        type: "browserPopup",
        modal: true,
        popupName: "우편번호 검색",
        width: 530,
        height: 400
    };

    var popupResult = await $c.win.openPopup("/ui/cm/zz/newzipcodePopup.xml", options, {});
    if (popupResult != null) {
        ed_zip.setValue(popupResult.zip);
        ed_addr1.setValue(popupResult.addr1);
        ed_addr2.focus();
    } else {
        ed_zip.setValue("");
        ed_addr1.setValue("");
        ed_zip.focus();
    }
};
